import type { ColorToken } from './color-palette.js';

/**
 * Base tooltip configuration shared across charts.
 * @internal
 */
export interface ChartTooltipConfig {
  hidden: boolean;
}

/**
 * Base tooltip config props for the chart config provider.
 * Charts can extend this to add chart-specific options.
 * @public
 */
export interface ChartTooltipConfigProps {
  /**
   * When true, hides the tooltip entirely.
   * @defaultValue false
   */
  hidden?: boolean;
}

/**
 * The tooltip display
 * @public
 */
export const seriesDisplayModeOptions = ['single-line', 'multi-line'] as const;

/**
 * @public
 */
export type SeriesDisplayMode = (typeof seriesDisplayModeOptions)[number];

/**
 * @public
 */
export interface TooltipItem extends Record<string, unknown> {
  id: string;
  name: string | string[];
  color?: ColorToken;
  values?: string[];
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  userData?: Record<string, any>;
}

/**
 * Whether the tooltip is single (only the closest series is displayed) or shared (all series in a timeframe are displayed)
 * @public
 */
export const tooltipVariantOptions = ['single', 'shared'] as const;

/**
 * @public
 */
export type TooltipVariant = (typeof tooltipVariantOptions)[number];
